import { describe, it, expect } from 'vitest';
import { richardsonLucyDeblur } from '../src/image-deblur-rl';
import { applyPSF, gaussianPSF } from '../src/image-psf';

function lcg(seed: number) {
  let s = seed >>> 0;
  return () => {
    s = (s * 1103515245 + 12345) & 0x7fffffff;
    return s / 0x7fffffff;
  };
}

function buildNaturalishPlane(w: number, h: number, seed: number): Float32Array {
  const plane = new Float32Array(w * h);
  const rand = lcg(seed);
  const cx = w / 2;
  const cy = h / 2;
  const radialScale = (Math.min(w, h) * Math.min(w, h)) / 16;
  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      const dx = x - cx;
      const dy = y - cy;
      const radial = Math.exp(-(dx * dx + dy * dy) / radialScale);
      const ripple = 0.15 * Math.sin(x / 5) * Math.cos(y / 4);
      const noise = 0.05 * (rand() - 0.5);
      let v = radial + ripple + noise;
      if (v < 0) v = 0;
      if (v > 1) v = 1;
      plane[y * w + x] = v;
    }
  }
  return plane;
}

function mse(a: Float32Array, b: Float32Array): number {
  let s = 0;
  for (let i = 0; i < a.length; i++) {
    const d = a[i]! - b[i]!;
    s += d * d;
  }
  return s / a.length;
}

describe('richardsonLucyDeblur — API and validation', () => {
  it('exists as an exported function', () => {
    expect(typeof richardsonLucyDeblur).toBe('function');
  });

  it('throws RangeError on non-pow2 w', () => {
    const w = 48; // not pow2
    const h = 64;
    const plane = new Float32Array(w * h);
    const psf = gaussianPSF(1.0, 11);
    expect(() =>
      richardsonLucyDeblur({ plane, w, h, psf, psfW: 11, psfH: 11 }),
    ).toThrow(RangeError);
  });

  it('throws RangeError on plane.length mismatch', () => {
    const w = 64;
    const h = 64;
    const plane = new Float32Array(w * h - 7); // wrong length
    const psf = gaussianPSF(1.0, 11);
    expect(() =>
      richardsonLucyDeblur({ plane, w, h, psf, psfW: 11, psfH: 11 }),
    ).toThrow(RangeError);
  });

  it('throws RangeError on even psfW', () => {
    const w = 64;
    const h = 64;
    const plane = new Float32Array(w * h);
    const psf = new Float32Array(10 * 11); // even psfW
    expect(() =>
      richardsonLucyDeblur({ plane, w, h, psf, psfW: 10, psfH: 11 }),
    ).toThrow(RangeError);
  });

  it('throws RangeError on iterations < 1', () => {
    const w = 64;
    const h = 64;
    const plane = new Float32Array(w * h);
    const psf = gaussianPSF(1.0, 11);
    expect(() =>
      richardsonLucyDeblur({ plane, w, h, psf, psfW: 11, psfH: 11, iterations: 0 }),
    ).toThrow(RangeError);
  });

  it('throws RangeError on epsilon <= 0', () => {
    const w = 64;
    const h = 64;
    const plane = new Float32Array(w * h);
    const psf = gaussianPSF(1.0, 11);
    expect(() =>
      richardsonLucyDeblur({ plane, w, h, psf, psfW: 11, psfH: 11, epsilon: 0 }),
    ).toThrow(RangeError);
    expect(() =>
      richardsonLucyDeblur({ plane, w, h, psf, psfW: 11, psfH: 11, epsilon: -1e-3 }),
    ).toThrow(RangeError);
  });
});

describe('richardsonLucyDeblur — recovery quality', () => {
  it('improves PSNR on a known-blurred fixture (MSE recovered < MSE blurred)', () => {
    const w = 64;
    const h = 64;
    const original = buildNaturalishPlane(w, h, 1);

    const psfSize = 11;
    const psf = gaussianPSF(1.5, psfSize);
    const blurred = applyPSF({ plane: original, w, h, psf, psfW: psfSize, psfH: psfSize });

    const recovered = richardsonLucyDeblur({
      plane: blurred,
      w,
      h,
      psf,
      psfW: psfSize,
      psfH: psfSize,
      iterations: 15,
    });

    const mseBlurred = mse(original, blurred);
    const mseRecovered = mse(original, recovered);

    expect(mseRecovered).toBeLessThan(mseBlurred);
  });

  it('preserves non-negativity on a non-negative input', () => {
    const w = 64;
    const h = 64;
    const original = buildNaturalishPlane(w, h, 2);

    // Sanity: builder is non-negative.
    for (let i = 0; i < original.length; i++) {
      expect(original[i]!).toBeGreaterThanOrEqual(0);
    }

    const psfSize = 11;
    const psf = gaussianPSF(1.5, psfSize);
    const blurred = applyPSF({ plane: original, w, h, psf, psfW: psfSize, psfH: psfSize });

    const recovered = richardsonLucyDeblur({
      plane: blurred,
      w,
      h,
      psf,
      psfW: psfSize,
      psfH: psfSize,
      iterations: 15,
    });

    for (let i = 0; i < recovered.length; i++) {
      expect(recovered[i]!).toBeGreaterThanOrEqual(0);
    }
  });

  it('more iterations recovers more (monotonically non-increasing MSE)', () => {
    const w = 64;
    const h = 64;
    const original = buildNaturalishPlane(w, h, 3);

    const psfSize = 11;
    const psf = gaussianPSF(1.5, psfSize);
    const blurred = applyPSF({ plane: original, w, h, psf, psfW: psfSize, psfH: psfSize });

    const recovered5 = richardsonLucyDeblur({
      plane: blurred,
      w,
      h,
      psf,
      psfW: psfSize,
      psfH: psfSize,
      iterations: 5,
    });
    const recovered15 = richardsonLucyDeblur({
      plane: blurred,
      w,
      h,
      psf,
      psfW: psfSize,
      psfH: psfSize,
      iterations: 15,
    });
    const recovered30 = richardsonLucyDeblur({
      plane: blurred,
      w,
      h,
      psf,
      psfW: psfSize,
      psfH: psfSize,
      iterations: 30,
    });

    const mse5 = mse(original, recovered5);
    const mse15 = mse(original, recovered15);
    const mse30 = mse(original, recovered30);

    // Loose monotonicity (allow slight float-noise floor at convergence).
    expect(mse15).toBeLessThanOrEqual(mse5 + 1e-6);
    expect(mse30).toBeLessThanOrEqual(mse5 + 1e-6);
  });

  it('still improves on a mild PSF (σ=0.5)', () => {
    const w = 64;
    const h = 64;
    const original = buildNaturalishPlane(w, h, 4);

    const psfSize = 11;
    const psf = gaussianPSF(0.5, psfSize);
    const blurred = applyPSF({ plane: original, w, h, psf, psfW: psfSize, psfH: psfSize });

    const recovered = richardsonLucyDeblur({
      plane: blurred,
      w,
      h,
      psf,
      psfW: psfSize,
      psfH: psfSize,
      iterations: 15,
    });

    const mseBlurred = mse(original, blurred);
    const mseRecovered = mse(original, recovered);

    expect(mseRecovered).toBeLessThan(mseBlurred);
  });
});
